                        // We'll use a nested loop over j0 in tile.
                        for (uint32_t j0 = 0; j0 < actualTile; j0++) {
                            float w_jk = w_i2hGm_.GetValue((j + j0) * K_ + k);
                            preLocal[j + j0] = preLocal[j + j0] + x_val * w_jk;
                        }
                    }
                    // Add bias
                    for (uint32_t j0 = 0; j0 < actualTile; j0++) {
                        preLocal[j + j0] = preLocal[j + j0] + b_i2hLocal[j + j0];
                    }
                }

                // Compute h = tanh(pre)
                AscendC::Tanh(hLocal, preLocal, H_);

                // Compute y_t = h * w_h2o.T + b_h2o
                AscendC::LocalTensor<float> ytLocal = ytBuf_.Get<float>();
                // For each o in O: yt[o] = dot(h, w_h2o[o]) + b_h2o[o]
                for (uint32_t o = 0; o < O_; o += tileO_) {
                    uint32_t actualTile = min(tileO_, O_ - o);
                    AscendC::SetZero(ytLocal[o], actualTile);
                    for (uint32_t hIdx = 0; hIdx < H_; hIdx++) {
                        float w = w_h2oGm_.GetValue((o) * H_ + hIdx); // Actually row o, col hIdx.
                        // We'll loop over o0
                        for (uint32_t o0 = 0; o0 < actualTile; o0++) {
                            float w_oh = w_h2oGm_.GetValue((o + o0) * H_ + hIdx);
                            ytLocal[o + o0] = ytLocal[o + o0] + hLocal[hIdx] * w_oh;
                        }
                    }
                    // Add bias
                    for (uint32_t o0 = 0; o0 < actualTile; o0++) {
                        ytLocal[o + o0] = ytLocal[o + o0] + b_h2oLocal[o + o0];
                    }
                }

                // Store y_t to global
                AscendC::DataCopy(yGm_[(t * B_ + b) * O_], ytLocal, O_);
            }
        }
    }

